"use client";

import { useState } from "react";
import Navbar from "@/app/components/Navbar";
import Footer from "@/app/components/Footer";
import SearchBar from "@/app/components/SearchBar";
import JobCard from "@/app/components/JobCard";
import JobFilters from "@/app/components/JobFilters";

interface Job {
    id: string;
    slug: string;
    title: string;
    location: string;
    salaryMin?: number;
    salaryMax?: number;
    jobType: string;
    skills: string[];
    createdAt: string;
    company: {
        name: string;
    };
}

interface Filters {
    industries: { id: string; name: string; slug: string }[];
    locations: string[];
    jobTypes: string[];
    salaryRanges: { value: string; label: string }[];
}

interface JobsPageClientProps {
    jobs: Job[];
    filters: Filters;
    searchParams: { q?: string; loc?: string; type?: string; industry?: string; salary?: string };
}

export default function JobsPageClient({ jobs, filters, searchParams }: JobsPageClientProps) {
    const [showFilters, setShowFilters] = useState(false);

    const currentIndustry = searchParams.industry
        ? filters.industries.find(i => i.slug === searchParams.industry)?.name
        : null;

    return (
        <div style={{ minHeight: "100vh", display: "flex", flexDirection: "column" }}>
            <Navbar />

            {/* Sub-header */}
            <div className="jobs-header">
                <div className="container-xl">
                    <h1 className="jobs-title">
                        Tìm kiếm việc làm
                        {searchParams.q && <span style={{ color: "var(--primary)" }}> &ldquo;{searchParams.q}&rdquo;</span>}
                        {currentIndustry && <span style={{ color: "var(--cta)" }}> - {currentIndustry}</span>}
                    </h1>
                    <SearchBar size="lg" />
                </div>
            </div>

            <main className="section-sm jobs-main">
                <div className="container-xl">
                    {/* Mobile filter toggle */}
                    <div className="jobs-filter-toggle hide-desktop">
                        <button
                            onClick={() => setShowFilters(!showFilters)}
                            className="btn-outline"
                            style={{ width: "100%", justifyContent: "center" }}
                        >
                            <svg width="16" height="16" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24">
                                <path strokeLinecap="round" strokeLinejoin="round" d="M3 4a1 1 0 011-1h16a1 1 0 011 1v2.586a1 1 0 01-.293.707l-6.414 6.414a1 1 0 00-.293.707V17l-4 4v-6.586a1 1 0 00-.293-.707L3.293 7.293A1 1 0 013 6.586V4z" />
                            </svg>
                            Bộ lọc {showFilters ? "▲" : "▼"}
                        </button>
                    </div>

                    {/* Collapsible filters on mobile */}
                    {showFilters && (
                        <div className="jobs-filters-mobile hide-desktop">
                            <JobFilters
                                industries={filters.industries}
                                locations={filters.locations}
                                jobTypes={filters.jobTypes}
                                salaryRanges={filters.salaryRanges}
                            />
                        </div>
                    )}

                    <div className="jobs-content">
                        {/* Sidebar - Desktop only */}
                        <aside className="jobs-sidebar hide-mobile">
                            <JobFilters
                                industries={filters.industries}
                                locations={filters.locations}
                                jobTypes={filters.jobTypes}
                                salaryRanges={filters.salaryRanges}
                            />
                        </aside>

                        {/* Job list */}
                        <div className="jobs-list">
                            <div className="jobs-header-row">
                                <p style={{ fontSize: "0.9375rem", color: "var(--text-muted)" }}>
                                    Tìm thấy <strong style={{ color: "var(--primary)" }}>{jobs.length}</strong> việc làm
                                    {currentIndustry && <span> trong ngành <strong>{currentIndustry}</strong></span>}
                                </p>
                                <select className="jobs-sort-select">
                                    <option>Mới nhất</option>
                                    <option>Lương cao nhất</option>
                                    <option>Lương thấp nhất</option>
                                </select>
                            </div>

                            {jobs.length === 0 ? (
                                <div className="card" style={{ padding: "4rem", textAlign: "center", color: "var(--text-muted)" }}>
                                    <svg width="48" height="48" fill="none" stroke="var(--border)" strokeWidth="1.5" viewBox="0 0 24 24" style={{ margin: "0 auto 1rem" }}>
                                        <circle cx="11" cy="11" r="8" /><path strokeLinecap="round" d="M21 21l-4.35-4.35" />
                                    </svg>
                                    <p style={{ fontWeight: 600 }}>Không tìm thấy việc làm phù hợp</p>
                                    <p style={{ fontSize: "0.875rem", marginTop: "0.5rem" }}>Thử thay đổi từ khóa hoặc bộ lọc</p>
                                </div>
                            ) : (
                                <div className="jobs-grid">
                                    {jobs.map((job) => (
                                        <JobCard
                                            key={job.id}
                                            id={job.slug}
                                            title={job.title}
                                            company={job.company.name}
                                            location={job.location}
                                            salary={job.salaryMin && job.salaryMax ? `${Math.round(job.salaryMin / 1000000)}–${Math.round(job.salaryMax / 1000000)} triệu` : "Thỏa thuận"}
                                            type={job.jobType}
                                            skills={job.skills}
                                            posted={new Date(job.createdAt).toLocaleDateString("vi-VN")}
                                            featured={false}
                                        />
                                    ))}
                                </div>
                            )}
                        </div>
                    </div>
                </div>
            </main>

            <Footer />

            <style jsx>{`
                .jobs-header {
                    background: linear-gradient(135deg, #F0F9FF, #E0F2FE);
                    border-bottom: 1.5px solid var(--border);
                    padding: 2.5rem 0;
                }
                .jobs-title {
                    font-size: clamp(1.5rem, 3vw, 2rem);
                    font-weight: 800;
                    color: var(--text);
                    margin-bottom: 1.25rem;
                }
                .jobs-main {
                    flex: 1;
                    background: var(--bg);
                }
                .jobs-filter-toggle {
                    margin-bottom: 1rem;
                }
                .jobs-filters-mobile {
                    margin-bottom: 1.5rem;
                }
                .jobs-content {
                    display: grid;
                    grid-template-columns: 260px 1fr;
                    gap: 2rem;
                    align-items: flex-start;
                }
                .jobs-header-row {
                    display: flex;
                    justify-content: space-between;
                    align-items: center;
                    margin-bottom: 1.25rem;
                    flex-wrap: wrap;
                    gap: 0.75rem;
                }
                .jobs-sort-select {
                    padding: 0.5rem 1rem;
                    border-radius: 8px;
                    border: 1.5px solid var(--border);
                    background: var(--bg-card);
                    color: var(--text);
                    font-family: inherit;
                    font-size: 0.875rem;
                    cursor: pointer;
                    outline: none;
                }
                .jobs-grid {
                    display: grid;
                    grid-template-columns: repeat(auto-fill, minmax(300px, 1fr));
                    gap: 1.125rem;
                }
                
                @media (max-width: 1024px) {
                    .jobs-content {
                        grid-template-columns: 1fr;
                    }
                }
                
                @media (max-width: 640px) {
                    .jobs-header {
                        padding: 1.5rem 0;
                    }
                    .jobs-title {
                        font-size: 1.25rem;
                        margin-bottom: 1rem;
                    }
                }
            `}</style>
        </div>
    );
}
