import Link from "next/link";
import SaveJobButton from "./SaveJobButton";

interface JobCardProps {
    id: string;
    title: string;
    company: string;
    location: string;
    salary: string;
    type: string; // Full-time, Part-time, Remote
    skills: string[];
    logo?: string;
    posted: string;
    featured?: boolean;
    saved?: boolean;
}

export default function JobCard({
    id,
    title,
    company,
    location,
    salary,
    type,
    skills,
    logo,
    posted,
    featured = false,
    saved = false,
}: JobCardProps) {
    const typeColors: Record<string, string> = {
        Remote: "#22C55E",
        "Full-time": "#0369A1",
        "Part-time": "#F59E0B",
        Internship: "#A855F7",
    };
    const typeColor = typeColors[type] ?? "#0369A1";

    return (
        <Link
            href={`/jobs/${id}`}
            style={{ textDecoration: "none", display: "block", height: "100%" }}
            className="card-clickable"
        >
            <article
                className="card"
                style={{
                    padding: "1.25rem",
                    position: "relative",
                    overflow: "hidden",
                    height: "100%",
                    display: "flex",
                    flexDirection: "column",
                }}
            >
                {featured && (
                    <div
                        style={{
                            position: "absolute",
                            top: 0,
                            left: 0,
                            right: 0,
                            height: "3px",
                            background: "linear-gradient(90deg, var(--primary), var(--cta))",
                        }}
                    />
                )}

                {/* Header */}
                <div style={{ display: "flex", alignItems: "flex-start", gap: "0.875rem", marginBottom: "0.75rem" }}>
                    {/* Company logo placeholder */}
                    <div
                        style={{
                            width: "44px",
                            height: "44px",
                            borderRadius: "10px",
                            background: logo ? "transparent" : "var(--tag-bg)",
                            border: "1.5px solid var(--border)",
                            display: "flex",
                            alignItems: "center",
                            justifyContent: "center",
                            flexShrink: 0,
                            fontSize: "1rem",
                            fontWeight: 700,
                            color: "var(--primary)",
                        }}
                    >
                        {logo ? (
                            <img src={logo} alt={company} style={{ width: "100%", height: "100%", objectFit: "cover", borderRadius: "10px" }} />
                        ) : (
                            company.charAt(0).toUpperCase()
                        )}
                    </div>

                    <div style={{ flex: 1, minWidth: 0 }}>
                        <h3
                            style={{
                                fontSize: "0.9375rem",
                                fontWeight: 700,
                                color: "var(--text)",
                                marginBottom: "0.125rem",
                                whiteSpace: "nowrap",
                                overflow: "hidden",
                                textOverflow: "ellipsis",
                            }}
                        >
                            {title}
                        </h3>
                        <p style={{ fontSize: "0.8125rem", color: "var(--text-muted)", fontWeight: 500, margin: 0 }}>{company}</p>
                    </div>

                    {/* Type badge */}
                    <span
                        style={{
                            padding: "0.2rem 0.625rem",
                            borderRadius: "100px",
                            fontSize: "0.6875rem",
                            fontWeight: 600,
                            background: `${typeColor}18`,
                            color: typeColor,
                            whiteSpace: "nowrap",
                            flexShrink: 0,
                        }}
                    >
                        {type}
                    </span>
                </div>

                {/* Meta */}
                <div style={{ display: "flex", gap: "1rem", marginBottom: "0.75rem", flexWrap: "wrap" }}>
                    {[
                        {
                            icon: "M17.657 16.657L13.414 20.9a1.998 1.998 0 0 1-2.827 0l-4.244-4.243a8 8 0 1 1 11.314 0z M15 11a3 3 0 1 1-6 0 3 3 0 0 1 6 0z",
                            text: location,
                        },
                        {
                            icon: "M12 8c-1.657 0-3 .895-3 2s1.343 2 3 2 3 .895 3 2-1.343 2-3 2m0-8c1.11 0 2.08.402 2.599 1M12 8V7m0 1v8m0 0v1m0-1c-1.11 0-2.08-.402-2.599-1M21 12a9 9 0 1 1-18 0 9 9 0 0 1 18 0z",
                            text: salary,
                        },
                    ].map((item) => (
                        <div
                            key={item.text}
                            style={{ display: "flex", alignItems: "center", gap: "0.25rem", color: "var(--text-muted)", fontSize: "0.8125rem" }}
                        >
                            <svg width="13" height="13" fill="none" stroke="currentColor" strokeWidth="1.75" viewBox="0 0 24 24">
                                <path strokeLinecap="round" strokeLinejoin="round" d={item.icon} />
                            </svg>
                            <span style={{ whiteSpace: "nowrap" }}>{item.text}</span>
                        </div>
                    ))}
                </div>

                {/* Skills */}
                <div className="job-card-skills" style={{ display: "flex", gap: "0.375rem", marginBottom: "0.75rem", flex: 1 }}>
                    {skills.slice(0, 3).map((skill) => (
                        <span key={skill} className="tag" style={{ fontSize: "0.75rem", padding: "0.125rem 0.5rem", flexShrink: 0, whiteSpace: "nowrap" }}>
                            {skill}
                        </span>
                    ))}
                    {skills.length > 3 && (
                        <span className="tag" style={{ background: "var(--border)", color: "var(--text-muted)", fontSize: "0.75rem", padding: "0.125rem 0.5rem", flexShrink: 0, whiteSpace: "nowrap" }}>
                            +{skills.length - 3}
                        </span>
                    )}
                </div>

                {/* Footer */}
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginTop: "auto" }}>
                    <span style={{ fontSize: "0.75rem", color: "var(--text-muted)" }}>{posted}</span>
                    <div style={{ display: "flex", alignItems: "center", gap: "0.5rem" }}>
                        <SaveJobButton jobId={id} initialSaved={saved} />
                        <span
                            style={{
                                fontSize: "0.8125rem",
                                fontWeight: 600,
                                color: "var(--primary)",
                                display: "flex",
                                alignItems: "center",
                                gap: "0.25rem",
                            }}
                        >
                            Xem
                            <svg width="12" height="12" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24">
                                <path strokeLinecap="round" strokeLinejoin="round" d="M9 5l7 7-7 7" />
                            </svg>
                        </span>
                    </div>
                </div>
            </article>
        </Link>
    );
}
